                {
                    processNonOptionToken(token);
                }
                else
                {
                    Option optInstance = options.getOption(opt);
                    if (currentOption != null && currentOption.hasArg())
                    {
                        tokens.add(token);
                        currentOption = null;
                    }
                    else
                    {
                        tokens.add(opt);
                        this.currentOption = optInstance;
                        if (pos != -1)
                        {
